template.script:
(function() {
  'use strict';

  /* ── state ────────────────────────────────────────────────── */
  var _year    = ;
  var _month   = ;
  var _rows    = [];
  var _selected = {};   // id → true

  /* ── utils ────────────────────────────────────────────────── */
  function fmt(n) {
    return Number(n).toLocaleString('en-SA', {minimumFractionDigits:0, maximumFractionDigits:0});
  }
  function hhmm(h) {
    h = Number(h) || 0;
    var sign = h < -0.01 ? '-' : '';
    var abs  = Math.abs(h);
    var hh   = Math.floor(abs);
    var mm   = Math.round((abs - hh) * 60);
    return sign + pad(hh) + ':' + pad(mm);
  }
  function pad(n) { return n < 10 ? '0'+n : ''+n; }
  function fmtD(n) { return Number(n).toFixed(1); }

  function getCsrf() {
    var m = document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/);
    return m ? decodeURIComponent(m[1]) : '';
  }

  async function postJson(url, data) {
    var body = new URLSearchParams(data);
    var resp = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'X-CSRFToken':  getCsrf()
      },
      body: body.toString()
    });
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    return await resp.json();
  }

  /* ── period ───────────────────────────────────────────────── */
  window.IPR = window.IPR || {};

  IPR.changePeriod = function(val) {
    var parts = val.split('-');
    window.location.href = '/my/instant-payroll?year=' + parts[0] + '&month=' + parts[1];
  };

  /* ── load ─────────────────────────────────────────────────── */
  IPR.loadData = async function() {
    document.getElementById('iprOverlay').classList.add('active');
    var dept = document.getElementById('deptFilter').value || '';
    try {
      var result = await postJson('/my/instant-payroll/data', {
        year:          _year,
        month:         _month,
        department_id: dept
      });
      _rows = result.rows || [];
      _selected = {};
      document.getElementById('chkAll').checked = false;
      document.getElementById('btnBatch').style.display = 'none';
      renderTable(_rows);
      renderSummary(_rows.length, result.grand_totals || {});
    } catch(e) {
      document.getElementById('iprBody').innerHTML =
        '<tr><td colspan="16" style="text-align:center;color:#dc2626;padding:32px">Error: ' + e.message + '</td></tr>';
    } finally {
      document.getElementById('iprOverlay').classList.remove('active');
    }
  };

  /* ── render rows ──────────────────────────────────────────── */
  function renderTable(rows) {
    var body = document.getElementById('iprBody');
    if (!rows.length) {
      body.innerHTML = '<tr><td colspan="16" style="text-align:center;color:#9ca3af;padding:40px">No employees found.</td></tr>';
      return;
    }
    var q = (document.getElementById('searchInput').value || '').toLowerCase();
    var visible = q ? rows.filter(function(r){ return r.name.toLowerCase().indexOf(q) >= 0; }) : rows;

    body.innerHTML = visible.map(function(r) {
      var diffCls  = r.diff > 0.01 ? 'text-pos' : r.diff < -0.01 ? 'text-neg' : 'text-muted-sm';
      var diffSign = r.diff > 0.01 ? '+' : '';
      var netCls   = r.net < 0 ? 'badge-net-neg' : 'badge-net-pos';
      var leaveCls = r.leave_balance > 0 ? 'badge-leave-bal-pos' : 'badge-leave-bal-neg';

      return [
        '<tr data-id="' + r.id + '">',
        /* sticky employee col */
        '<td class="ipr-sticky">',
        '  <div style="display:flex;align-items:flex-start;gap:7px">',
        '    <input type="checkbox" class="emp-chk no-print" value="' + r.id + '"',
        '           ' + (_selected[r.id] ? 'checked' : '') + ' onchange="IPR.onCheck(this)"',
        '           style="margin-top:3px;cursor:pointer"/>',
        '    <div>',
        r.is_on_leave_now ? '      <span class="badge-leave">On Leave</span><br/>' : '',
        '      <span style="font-weight:700">' + r.name + '</span>',
        r.job ? '<br/><span class="text-muted-sm">' + r.job + '</span>' : '',
        '    </div>',
        '  </div>',
        '</td>',
        /* dept */
        '<td class="no-print text-muted-sm" style="text-align:center">' + (r.department||'') + '</td>',
        /* hours */
        '<td style="text-align:right;font-family:monospace;font-weight:700">' + hhmm(r.worked_hours) + '</td>',
        /* diff */
        '<td class="' + diffCls + '" style="text-align:right;font-family:monospace">' + diffSign + hhmm(r.diff) + '</td>',
        /* shifts */
        '<td class="no-print text-muted-sm" style="text-align:center">' + r.shift_count + '</td>',
        /* days */
        '<td class="no-print text-muted-sm" style="text-align:center">' + r.days_worked + '/' + r.expected_days + '</td>',
        /* gross */
        '<td style="text-align:right;font-family:monospace;font-weight:700;color:#4F46E5">' + fmt(r.gross) + '</td>',
        /* day ded */
        '<td style="text-align:right;font-family:monospace;color:#dc2626">' + (r.absent_ded > 0.01 ? '-'+fmt(r.absent_ded) : '—') + '</td>',
        /* hr ded */
        '<td style="text-align:right;font-family:monospace;color:#dc2626">' + (r.hourly_ded > 0.01 ? '-'+fmt(r.hourly_ded) : '—') + '</td>',
        /* total ded */
        '<td style="text-align:right;font-family:monospace;font-weight:700;color:#dc2626">' + (r.deduction > 0.01 ? fmt(r.deduction) : '—') + '</td>',
        /* ot */
        '<td style="text-align:right;font-family:monospace;font-weight:700;color:#16a34a">' + (r.overtime > 0.01 ? '+'+fmt(r.overtime) : '—') + '</td>',
        /* absent days — computed + adj input */
        '<td style="text-align:center">',
        '  <span style="font-weight:700;color:#dc2626;font-size:.72rem">' + fmtD(r.absent_from_leave) + '</span><br/>',
        '  <input type="number" step="0.5" class="adj-input red no-print"',
        '         value="' + (r.adj_absent || '') + '"',
        '         placeholder="Adj"',
        '         title="Extra absent days"',
        '         onchange="IPR.saveAdj(' + r.id + ', \'absent_days_adjustment\', this.value)"/>',
        '</td>',
        /* other ded */
        '<td class="no-print" style="text-align:center">',
        '  <input type="number" step="1" class="adj-input red"',
        '         value="' + (r.adj_other_ded || '') + '"',
        '         placeholder="0"',
        '         title="Extra deductions"',
        '         onchange="IPR.saveAdj(' + r.id + ', \'other_deductions\', this.value)"/>',
        '</td>',
        /* reimb */
        '<td class="no-print" style="text-align:center">',
        '  <input type="number" step="1" class="adj-input green"',
        '         value="' + (r.reimb || '') + '"',
        '         placeholder="0"',
        '         title="Reimbursements"',
        '         onchange="IPR.saveAdj(' + r.id + ', \'reimbursements\', this.value)"/>',
        '</td>',
        /* net */
        '<td style="text-align:right">',
        '  <span class="' + netCls + '">' + fmt(r.net) + '</span>',
        '</td>',
        /* leave balance */
        '<td class="no-print" style="text-align:center">',
        '  <span class="' + leaveCls + '" title="Allocated: ' + fmtD(r.leave_alloc_total) + 'd | Taken: ' + fmtD(r.leave_taken_ytd) + 'd">',
        '    ' + fmtD(r.leave_balance) + ' d',
        '  </span>',
        '</td>',
        '</tr>'
      ].join('');
    }).join('');
  }

  /* ── summary cards ────────────────────────────────────────── */
  function renderSummary(count, g) {
    document.getElementById('sEmp').textContent   = count;
    document.getElementById('sHours').textContent = hhmm(g.worked_hours||0);
    document.getElementById('sGross').textContent = fmt(g.gross||0);
    document.getElementById('sDed').textContent   = fmt(g.deduction||0);
    document.getElementById('sOT').textContent    = '+' + fmt(g.overtime||0);
    document.getElementById('sNet').textContent   = fmt(g.net||0);
    document.getElementById('summaryRow').style.display = 'block';

    document.getElementById('ftHours').textContent   = hhmm(g.worked_hours||0);
    document.getElementById('ftGross').textContent   = fmt(g.gross||0);
    document.getElementById('ftDed').textContent     = fmt(g.deduction||0);
    document.getElementById('ftOT').textContent      = '+' + fmt(g.overtime||0);
    document.getElementById('ftNet').textContent     = fmt(g.net||0);
    document.getElementById('ftOtherDed').textContent = fmt(g.other_ded||0);
    document.getElementById('ftReimb').textContent   = fmt(g.reimb||0);
    document.getElementById('iprFoot').style.display = '';
  }

  /* ── search filter ────────────────────────────────────────── */
  IPR.filterTable = function() { renderTable(_rows); };

  /* ── save adjustment (debounced) ─────────────────────────── */
  var _adjBuf = {};
  var _adjTmr = {};

  IPR.saveAdj = function(empId, field, rawVal) {
    var val = parseFloat(rawVal) || 0;
    if (!_adjBuf[empId]) _adjBuf[empId] = {};
    _adjBuf[empId][field] = val;
    clearTimeout(_adjTmr[empId]);
    _adjTmr[empId] = setTimeout(async function() {
      var buf = _adjBuf[empId];
      var row = _rows.find(function(r){ return r.id === empId; }) || {};
      try {
        await postJson('/my/instant-payroll/save-adjustment', {
          employee_id:           empId,
          year:                  _year,
          month:                 _month,
          other_deductions:      buf.other_deductions      !== undefined ? buf.other_deductions      : (row.adj_other_ded||0),
          reimbursements:        buf.reimbursements        !== undefined ? buf.reimbursements        : (row.reimb||0),
          absent_days_adjustment: buf.absent_days_adjustment !== undefined ? buf.absent_days_adjustment : (row.adj_absent||0)
        });
        IPR.loadData();
      } catch(e) { console.error('Save adj failed', e); }
    }, 900);
  };

  /* ── export CSV ───────────────────────────────────────────── */
  IPR.exportCsv = function() {
    if (!_rows.length) return;
    var headers = ['Employee','Department','Worked Hours','Diff (h)','Gross (SAR)',
                   'Day Deduction','Hour Deduction','Total Deduction','Overtime',
                   'Absent Days','Other Ded.','Reimb.','Net (SAR)','Leave Balance (d)'];
    var rows = _rows.map(function(r) {
      return [r.name, r.department, hhmm(r.worked_hours), r.diff.toFixed(2),
              r.gross, r.absent_ded, r.hourly_ded, r.deduction, r.overtime,
              r.total_absent, r.adj_other_ded, r.reimb, r.net, r.leave_balance];
    });
    var csv = [headers].concat(rows).map(function(row) {
      return row.map(function(v){ return '"' + String(v).replace(/"/g,'""') + '"'; }).join(',');
    }).join('\n');
    var blob = new Blob([csv], {type:'text/csv;charset=utf-8;'});
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'Payroll_' + _year + '_' + pad(_month) + '.csv';
    link.click();
  };

  /* ── checkbox logic ───────────────────────────────────────── */
  IPR.onCheck = function(el) {
    var id = parseInt(el.value);
    if (el.checked) _selected[id] = true;
    else delete _selected[id];
    var hasAny = Object.keys(_selected).length > 0;
    document.getElementById('btnBatch').style.display = hasAny ? 'inline-flex' : 'none';
  };

  IPR.toggleAll = function(el) {
    document.querySelectorAll('.emp-chk').forEach(function(chk) {
      chk.checked = el.checked;
      IPR.onCheck(chk);
    });
  };

  /* ── push to payroll batch ────────────────────────────────── */
  IPR.createBatch = async function() {
    var ids = Object.keys(_selected);
    if (!ids.length) return;
    if (!confirm('Create a payroll batch for ' + ids.length + ' selected employee(s)?')) return;
    try {
      var result = await postJson('/my/instant-payroll/create-batch', {
        year:         _year,
        month:        _month,
        employee_ids: JSON.stringify(ids.map(Number))
      });
      if (result.status === 'ok') {
        alert('✅ Batch created with ' + result.slips_created + ' payslip(s). Opening…');
        window.location.href = result.batch_url;
      } else {
        alert('⚠️ ' + result.message);
      }
    } catch(e) { alert('Error: ' + e.message); }
  };

  /* ── auto-load ────────────────────────────────────────────── */
  document.addEventListener('DOMContentLoaded', function() {
    IPR.loadData();
  });

})();
